patch:
--- a/priority_encoder.v
+++ b/priority_encoder.v
@@ -8,7 +8,7 @@
   output reg valid
 );

-  always @(req_lines) begin
+  always @(*) begin
     valid = 1'b0;
     priority_out = 3'b000;
     if (req_lines[7])

before_code:
module priority_encoder(
  input [7:0] req_lines,
  output reg [2:0] priority_out,
  output reg valid
);

  always @(req_lines) begin
    valid = 1'b0;
    priority_out = 3'b000;
    if (req_lines[7])
      priority_out = 3'b111;
    else if (req_lines[6])
      priority_out = 3'b110;
    else if (req_lines[5])
      priority_out = 3'b101;
    else if (req_lines[4])
      priority_out = 3'b100;
    else if (req_lines[3])
      priority_out = 3'b011;
    else if (req_lines[2])
      priority_out = 3'b010;
    else if (req_lines[1])
      priority_out = 3'b001;
    else if (req_lines[0])
      priority_out = 3'b000;
    else
      valid = 1'b1;
  end

endmodule

